  /// Initialize ObjectBox store
  ///
  /// Must be called before any database operations.
  /// Call during app initialization after dependencies are ready.
  Future<void> initialize() async {
    if (_isInitialized) {
      developer.log('ObjectBox already initialized', name: _logName);
      return;
    }

    try {
      final appDocDir = await getApplicationDocumentsDirectory();
      final dbPath = p.join(appDocDir.path, 'avrai_objectbox');

      // Ensure directory exists
      final dbDir = Directory(dbPath);
      if (!dbDir.existsSync()) {
        dbDir.createSync(recursive: true);
      }

      // NOTE: Actual store initialization requires generated code from build_runner
      // After running: dart run build_runner build
      // Uncomment and use:
      // _store = await openStore(directory: dbPath);
      // _decoherencePatternBox = _store.box<DecoherencePatternEntity>();
      // _quantumStateBox = _store.box<QuantumStateEntity>();
      // _ragEmbeddingBox = _store.box<RAGEmbeddingEntity>();
      // _structuredFactsBox = _store.box<StructuredFactsEntity>();

      _isInitialized = true;
      developer.log('ObjectBox initialized at: $dbPath', name: _logName);
    } catch (e, st) {
      developer.log(
        'Failed to initialize ObjectBox: $e',
        name: _logName,
        error: e,
        stackTrace: st,
      );
      rethrow;
    }
  }

  /// Close the store
  Future<void> close() async {
    if (!_isInitialized) return;

    try {
      // _store?.close();
      _isInitialized = false;
      developer.log('ObjectBox closed', name: _logName);
    } catch (e) {
      developer.log('Error closing ObjectBox: $e', name: _logName);
    }
  }

