  /// Update coherence level
  Future<void> updateCoherenceLevel(
      String agentId, double coherenceLevel) async {
    _ensureInitialized();
    final state = await getQuantumState(agentId);
    if (state != null) {
      state.coherenceLevel = coherenceLevel;
      state.lastMeasurement = DateTime.now();
      state.measurementCount++;
      await saveQuantumState(state);
    }
  }

